class Person:
    def __init__(self, förnamn, efternamn, födelseår):
      self.förnamn = förnamn
      self.efternamn = efternamn
      self.födelseår = födelseår

    def __repr__(self):
      return self.förnamn + " född " + str(self.födelseår)

    def skrivIntro(self):
      print("Hej jag heter " + self.förnamn + " " + self.efternamn + " och jag är född" + str(self.födelseår))

class Student(Person):

  def __init__(self, förnamn, efternman, födelseår, nivå="kandiat"):
    super().__init__(förnamn, efternman, födelseår)
    self.nivå= "kandidat"

  def masterNivå(self):
    self.nivå = "master"

student = Student("Petra", "Teknolog", 1997)
print(str(student) +  " pluggar nu på " + student.nivå + "-nivå")
print("Men hon fick precis ut sin examen.")
student.masterNivå()
print(str(student) +  " pluggar nu på " + student.nivå + "-nivå")
